type LeaderboardEntry struct {
	Name    string
	Wins    int
	Losses  int
	Goals   int
	Assists int
}

type MatchEntry struct {
	ID     string
	TeamA  string
	TeamB  string
	ScoreA int
	ScoreB int
	Date   string
}

func (m MatchEntry) WinnerClass(team string) string {
	if m.ScoreA == m.ScoreB {
		return "p-3 text-center"
	}
	if team == "a" && m.ScoreA > m.ScoreB {
		return "p-3 text-center font-bold text-turf"
	}
	if team == "b" && m.ScoreB > m.ScoreA {
		return "p-3 text-center font-bold text-turf"
	}
	return "p-3 text-center"
}

func inlineMemberName(m repository.MemberInfo) string {
	if m.FirstName != "" || m.LastName != "" {
		return m.FirstName + " " + m.LastName
	}
	return m.Email
}

func inlineIntString(n int) string {
	return javaScriptSafeInt(n)
}

func javaScriptSafeInt(n int) string {
	return javaScriptSafeIntStr(n)
}

func javaScriptSafeIntStr(n int) string {
	switch n {
	case 0:
		return "0"
	case 1:
		return "1"
	case 2:
		return "2"
	case 3:
		return "3"
	case 4:
		return "4"
	case 5:
		return "5"
	case 6:
		return "6"
	case 7:
		return "7"
	case 8:
		return "8"
	case 9:
		return "9"
	default:
		// Convert simple int
		res := ""
		for n > 0 {
			res = string(rune('0'+n%10)) + res
			n /= 10
		}
		if res == "" {
			return "0"
		}
		return res
	}
}

